-- CreateIndex
CREATE INDEX "assessments_school_id_class_arm_id_term_id_idx" ON "assessments"("school_id", "class_arm_id", "term_id");

-- CreateIndex
CREATE UNIQUE INDEX "assessments_school_id_student_id_subject_id_term_id_key" ON "assessments"("school_id", "student_id", "subject_id", "term_id");

-- AddForeignKey
ALTER TABLE "assessment_scores" ADD CONSTRAINT "assessment_scores_component_id_fkey" FOREIGN KEY ("component_id") REFERENCES "grading_components"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

-- ---------------------------------------------------------------------
-- Slice 2 RLS policies (verbatim from prisma/policies/phase-2.sql).
-- Both tables carry their own school_id → flat direct-column check, NOT
-- EXISTS-through-component. FORCE so the migration role cannot bypass.
-- ---------------------------------------------------------------------

ALTER TABLE "assessment_scores" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "assessment_scores" FORCE  ROW LEVEL SECURITY;
ALTER TABLE "assessments"       ENABLE ROW LEVEL SECURITY;
ALTER TABLE "assessments"       FORCE  ROW LEVEL SECURITY;

CREATE POLICY tenant_isolation ON "assessment_scores"
  USING      (school_id::text = current_setting('app.current_school_id', true))
  WITH CHECK (school_id::text = current_setting('app.current_school_id', true));

CREATE POLICY tenant_isolation ON "assessments"
  USING      (school_id::text = current_setting('app.current_school_id', true))
  WITH CHECK (school_id::text = current_setting('app.current_school_id', true));
